// LLM1 BATCHED — parallel über n8n-nativen HTTP-Helper (echte Netzwerkschicht)
const items = $input.all();

const MODEL       = "qwen3.6-35b-mtp";                                    // llama-swap-Key!
const URL         = "YOUR_LLM_ENDPOINT/v1/chat/completions";
const AUTH        = "Bearer YOUR_API_KEY";
const CONCURRENCY = 8;   // == -np

const buildBody = (j) => ({
  model: MODEL,
  response_format: { type: "json_object" },
  messages: [
    { role: "system", content: j.rawSystempromptText },
    { role: "user",   content: j.rawPromptText }
  ],
  temperature: 0.1, top_p: 0.8, top_k: 20,
  presence_penalty: 0.0, frequency_penalty: 0.0,
  max_tokens: 2048,
  chat_template_kwargs: { enable_thinking: false },
});

// Arrow-Funktionen, damit `this` (= n8n-Kontext) erhalten bleibt
const callOne = async (j) => {
  try {
    const data = await this.helpers.httpRequest({
      method: 'POST',
      url: URL,
      headers: { Authorization: AUTH },
      body: buildBody(j),
      json: true,
      timeout: 600000,
    });
    const choice = data?.choices?.[0];
    const msg    = choice?.message;
    let content  = msg?.content || "";
    if (!content && msg?.reasoning_content) content = msg.reasoning_content;  // Fallback
    return {
      ...j,
      final_response: content || null,
      _finish: choice?.finish_reason ?? null,
      _completion_tokens: data?.usage?.completion_tokens ?? null,
      _reasoning_len: (msg?.reasoning_content || "").length, 
    };
  } catch (e) {
    return { ...j, final_response: null, _llm1_error: (e?.message || String(e)).slice(0, 300) };
  }
};

const runPool = async (list, limit) => {
  const results = new Array(list.length);
  let idx = 0;
  const worker = async () => {
    while (idx < list.length) { const i = idx++; results[i] = await callOne(list[i].json); }
  };
  await Promise.all(Array.from({ length: Math.min(limit, list.length) }, worker));
  return results;
};

const out = await runPool(items, CONCURRENCY);

// Diagnose: wenn ALLES fehlschlägt, Node bewusst rot werfen (statt still null)
if (out.length && out.every(o => o.final_response == null)) {
  throw new Error('LLM1: kein erfolgreicher Call. Erster Fehler: ' + (out[0]._llm1_error || 'unbekannt'));
}

return out.map((json) => ({ json }));

