// =====================================================================
// DATA NORMALIZER: Macht die Daten einheitlich (egal ob Start oder Webhook)
// =====================================================================

const data = $input.item.json;

// Wenn 'body' existiert (Webhook), packe es aus. Ansonsten nimm die Daten direkt (Start-Node).
const cleanData = data.body ? data.body : data;

return {
  json: cleanData
};

// =====================================================================
// CODE-NODE: Flatten — Cluster → ein Item pro Begriff (nach Normalize_Input)
// =====================================================================
const data = $input.item.json;
const CLUSTERS = ["Objekttyp","Thema_Phänomen","Inhalt_Motiv","Funktion_Zweck",
  "Visuelle_Merkmale","Form_Gestalt","Bestandteile","Gebrauchskontext",
  "Kultureller_Kontext","Emotion_Atmosphäre","Farbe_Nuancen"];

const caption  = data.caption  || data.Caption  || "";
const metadata = data.metadata || data.Metadata || data.context_data_string || "";

const out = [];
let n = 0;
for (const cluster of CLUSTERS) {
  const arr = Array.isArray(data[cluster]) ? data[cluster] : [];
  for (const it of arr) {
    if (!it || !it.term) continue;
    out.push({ json: {
      id: String(++n),
      cluster,
      term: it.term,
      why: it.why || "",
      judge_comment: it.judge_comment || "",
      caption,
      metadata
    }});
  }
}
return out;

// =====================================================================
// CODE-NODE: done-Aggregator — Linear & Flach
// =====================================================================
const items = $input.all();
const byCluster = {};
const errors = [];

function safeParseJson(rawInput) {
  if (!rawInput) return null;
  if (typeof rawInput === 'object') return rawInput;
  try {
    let cleanString = rawInput.trim();
    const startIdx = cleanString.indexOf('{');
    const endIdx = cleanString.lastIndexOf('}');
    if (startIdx !== -1 && endIdx !== -1) {
      cleanString = cleanString.substring(startIdx, endIdx + 1);
      return JSON.parse(cleanString);
    }
  } catch (e) {
    return null;
  }
  return null;
}

for (const it of items) {
  const j = it.json;
  const v = safeParseJson(j.gnd_result_raw);

  const cluster  = (v && v.cluster) || j.cluster || "Unsorted";
  const termName = (v && v.term)    || j.term    || "N/A";

  if (!v) {
    const reason = j._skip === "empty_llm1"
      ? "LLM1 lieferte keine Antwort (leer/abgeschnitten)."
      : "Parsing-Fehler: Ungültiges JSON.";
    errors.push({ id: j.id, term: termName, cluster, reason });
    (byCluster[cluster] ||= []).push({
      term:               termName,
      gnd_name:           null,
      gnd_id:             null,
      confidence:         "no_match",
      llm2_rationale:     j.why || "",
      llm3_judge_comment: j.judge_comment || "",
      llm4_reasoning:     reason
    });
    continue;
  }

  (byCluster[cluster] ||= []).push({
    term:               v.term,
    gnd_name:           v.gnd_preferred_name ?? null,
    gnd_id:             v.gnd_id ?? null,
    confidence:         v.gnd_confidence || "no_match",
    llm2_rationale:     j.why || "",
    llm3_judge_comment: j.judge_comment || "",
    llm4_reasoning:     v.reasoning || ""
  });
}

return [{ json: {
  gnd_result_string: JSON.stringify(byCluster, null, 2),
  _error_count: errors.length,
  _errors: errors
}}];

// =====================================================================
// BATCH RETRIEVAL: Alle Terme auf einmal gegen GND/_msearch
// =====================================================================

const items = $input.all();

// _msearch erwartet: pro Anfrage zwei Zeilen (header + body), newline-getrennt
// header: { "index": "gnd_sachbegriffe" }
// body:   { "size": 5, "query": { ... } }

const lines = [];

for (const item of items) {
  const term = item.json.term;

  // Header-Zeile
  lines.push(JSON.stringify({ index: "gnd_sachbegriffe" }));

  // Query-Zeile – gleiche Felder und Gewichtung wie der bisherige Einzel-Search
  lines.push(JSON.stringify({
    size: 5,
    query: {
      multi_match: {
        query: term,
        fields: [
          "preferred_name^5",
          "alternate_names^3",
          "broader_term^2",
          "related_term^1",
          "def^1"
        ],
        fuzziness: "AUTO"
      }
    },
    _source: ["preferred_name", "alternate_names", "def", "gnd_id"]
  }));
}

// _msearch braucht einen abschließenden Newline
const msearchBody = lines.join("\n") + "\n";

return [{ json: { msearchBody, items: items.map(i => i.json) } }];

// =====================================================================
// CODE-NODE: Inject_GND_Matches (Die Daten-Brücke nach dem Bulk-Search)
// =====================================================================

// 1. Hole die rohen Suchergebnisse aus dem OpenSearch-Response
const osResponse = $node["HTTP Request11"].json;
const searchResponses = osResponse.responses || [];

// 2. Hole die ursprünglichen, flachgeklopften Begriffe aus der vorgelagerten Node
// (Wir lesen die gemappten Items aus 'Code in JavaScript2')
const originalPayload = $('OpenSearch_Bulk_Prep').first().json;
const originalItems = originalPayload.items || [];

const enrichedItems = [];

// 3. Iteriere über die Items und verheirate sie mit den Hits
for (let i = 0; i < originalItems.length; i++) {
  const item = originalItems[i];
  const osHit = searchResponses[i];

  // Extrahiere die echten Treffer-Dokumente (wir haben size: 5 gesetzt)
  const hits = osHit?.hits?.hits || [];

  // Wir mappen die Hits in ein sauberes, flaches Array für das LLM
  const gndCandidates = hits.map(h => ({
    gnd_id: h._source.gnd_id || null,
    preferred_name: h._source.preferred_name || null,
    alternate_names: h._source.alternate_names || null,
    definition: h._source.def || null // 'def' im Index gemappt
  }));

  // Gib dem Item die Kandidaten mit
  enrichedItems.push({
    json: {
      ...item,
      gnd_candidates: gndCandidates,
      has_candidates: gndCandidates.length > 0
    }
  });
}

return enrichedItems;

// Ersetzt phi (LLM2): deterministische Konsolidierung, kein LLM-Call
const FLAGS = ["DESCRIPTIVE_NO_GND","DEFINITION_MISMATCH","MULTIPLE_CANDIDATES","SYNONYM_USED","LOW_FUZZY_OVERLAP"];

function parseJson(raw) {
  if (!raw) return null;
  if (typeof raw === 'object') return raw;
  let s = String(raw).replace(/```json/gi,'').replace(/```/g,'').trim();
  const a = s.indexOf('{'), b = s.lastIndexOf('}');
  if (a !== -1 && b !== -1) s = s.slice(a, b + 1);
  try { return JSON.parse(s); } catch { return null; }
}

function scoreFromTags(tags) {
  const t = Array.isArray(tags) ? tags.join(' ') : String(tags || '');
  const hits = FLAGS.filter(f => t.includes(f)).length;
  return Math.min(1.0, Math.round(hits * 0.2 * 100) / 100);
}

return $input.all().map((item) => {
  const j = item.json;

  if (!j.final_response) {
    return { json: { ...j, gnd_result_raw: null, _skip: "empty_llm1" } };
  }

  const v = parseJson(j.final_response);
  if (!v) {
    return { json: { ...j, gnd_result_raw: null, _parse_error: "llm1_unparsable" } };
  }

  const conf = v.gnd_confidence || "no_match";
  let gnd_id = v.gnd_id;
  if (gnd_id === "null" || gnd_id === "" || gnd_id === undefined) gnd_id = null;
  if (conf === "no_match") gnd_id = null;   // Regel: no_match ⇒ keine ID

  const gnd_result_raw = {
    id:                 j.id,
    cluster:            j.cluster,
    term:               j.term,
    gnd_id,
    gnd_preferred_name: v.gnd_preferred_name ?? null,
    gnd_confidence:     conf,
    unsicherheit_score: scoreFromTags(v.debug_tags),
    reasoning:          v.reasoning || "",
    debug_tags:         v.debug_tags || "NONE",
    additional_data:    v.additional_data || { alternate_names: null, definition: null }
  };

  return { json: { ...j, gnd_result_raw } };
});
